source:
Job Foundry Hub
https://jobfoundryhub.com
{% now "D, d M Y H:i:s O" %}
{% for job in jobs %}

  {{ job.title }}
  {{ job.posted_at|date:"D, d M Y H:i:s O" }}
  {{ job.id }}
  {{ site_url }}{{ job.get_absolute_url }}
  {{ job.company.name }}
  {{ job.location }}
  {{ job.region }}
  {{ job.country }}
  {{ job.description|striptags|safe }}
  {% if job.salary_min %}{{ job.salary_currency }} {{ job.salary_min }}{% if job.salary_max %} - {{ job.salary_max }}{% endif %} per {{ job.salary_period }}{% endif %}
  {{ job.job_type }}
  {{ job.category.name|default:"General" }}
  {{ job.experience_level }}
  {% if job.is_remote %}true{% endif %}

{% endfor %}
